  ('disabled-6f0ba476-moex-00283', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-112-e0b1f2ed', 'sub-disabled-6f0ba476-02', NULL, 'single_choice', '甲公司 X1 年 12 月 31 日來自營運活動現金流入為$26,250，X1 年整年度 折舊費用為$11,250，X1 年 12 月 31 日僅出售一個機器設備，收到現金 $12,000，該設備之原始成本$27,000，出售時該設備之累計折舊為$14,250 ，該設備之帳面金額為$12,750，X1年期間應收票據增加$21,000，存貨減 少$15,000，應付利息增加$6,000，應付所得稅減少$4,500，試問甲公司X1 年度損益表中的本期淨利為何？', '["$18,750", "$33,750", "$19,500", "$34,500 30650"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:29+00:00", "source_pdf_sha1": "998de82ed70f", "answer_pdf_sha1": "6717b96c0f3e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "305", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00284', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-112-e0b1f2ed', 'sub-disabled-6f0ba476-02', NULL, 'single_choice', '假設在X1年7月1日，甲公司的股東同意給予公司經理10,000個選擇權購 買普通股，該普通股面額為$90。公司給予選擇權的日期為 X2 年 1 月 1 日 ，經理可在未來 10 年內的任何時間行使該選擇權，每個選擇權能讓經理以 每股價格$5,000購買普通股，假設：⑴公司以公允價值計算該計畫總獎酬費 用是$24,000,000 ⑵該計畫X2 年1 月1 日實施後能為公司帶來2 年效益， 需在此兩年攤提該計畫獎酬費用。甲公司的經理在 X5 年 12 月 31 日行使 2,000個選擇權，X1年至X5年公司會計報表表達何者正確？', '["X1/12/31損益表表達：薪資支出 $24,000,000", "X2/12/31資產負債表中股東權益項下表達： 資本公積-員工認股權 $24,000,000", "X5/12/31資產負債表中股東權益項下表達： 股本-普通股 $ 180,000 股本溢價-普通股 14,620,000 資本公積-員工認股權 19,200,000", "X5/12/31資產負債表中股東權益項下表達： 股本-普通股 $ 180,000 股本溢價-普通股 9,820,000 資本公積-員工認股權 12,000,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:29+00:00", "source_pdf_sha1": "998de82ed70f", "answer_pdf_sha1": "6717b96c0f3e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "305", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00285', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-112-e0b1f2ed', 'sub-disabled-6f0ba476-02', NULL, 'single_choice', '甲公司設立桌上型電腦、筆記型電腦和平板電腦三個部門，平板電腦部門 經營不善，故X5年7月31日決定要將平板電腦部門停止營運，並出售處 分平板電腦部門的設備資產共獲利$30,000，甲公司加總三個部門X5年的 總收入$1,900,000 作為損益表的營業收入，並加總三個部門 X5 年的總費 用$1,300,000 作為營業費用，實際上，甲公司損益表中$1,900,000 的營業 收入中包括平板電腦部門X5年1月1日至X5年7月31日的收入$300,000 ，甲公司損益表中$1,300,000 的營業費用中包括平板電腦部門 X5 年 1 月 1日至X5年7月31日的費用$360,000，所得稅率為30%，請問上述甲公 司損益表表達停止營運的平板電腦部門是否正確？', '["上述損益表表達正確，損益表不必獨立揭露停業部門-平板電腦部門的損 益，亦不需揭露處分停業部門資產利益$30,000", "損益表表達正確，損益表不必獨立揭露停業部門-平板電腦部門的損益， 只需揭露處分停業部門資產稅後利益$21,000", "上述損益表表達不正確，損益表應該獨立揭露停業部門-平板電腦部門的 損益訊息如下： 停業部門的營運稅後損失 $(42,000) 處分停業部門資產稅後利益 21,000 停業部門稅後損失 $(21,000)", "上述損益表表達不正確，損益表應該獨立揭露停業部門-平板電腦部門的 損益訊息，但不必考慮稅如下： 停業部門的營運收入 $300,000 停業部門的營運費用 (360,000) 停業部門的損失 $(60,000) 處分停業部門資產利益 30,000 停業部門損失 $(30,000) 30650"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:29+00:00", "source_pdf_sha1": "998de82ed70f", "answer_pdf_sha1": "6717b96c0f3e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "305", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00286', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-112-e0b1f2ed', 'sub-disabled-6f0ba476-02', NULL, 'single_choice', '試以下列資料運用毛利法推算期末存貨： 期初存貨 $ 400,000 本期進貨淨額 5,000,000 本期銷貨淨額 6,000,000 估計毛利率 20%', '["$600,000", "$1,200,000", "$2,400,000", "$4,800,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:29+00:00", "source_pdf_sha1": "998de82ed70f", "answer_pdf_sha1": "6717b96c0f3e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "305", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00287', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-112-e0b1f2ed', 'sub-disabled-6f0ba476-02', NULL, 'single_choice', '甲公司X3 年全年普通股發行流通在外2,000,000 股。甲公司另於X1 年1 月2日發行10年期5,000張面值$1,000，10%的可轉換公司債，每張公司 債可轉換 15 股普通股，二年後 X3 年起會提高到每張可轉換公司債可轉 換 18 股普通股。該可轉換公司債每年付利息一次，並且，該可轉換公司 債負債部分的利息費用為每年$400,000，自X1年至X3年並無公司債轉換 為普通股，X3年度淨利為$8,000,000，所得稅率為30%，試問（答案四捨 五入至小數點後二位）：', '["該公司X3年度稀釋每股盈餘為$3.96", "該公司X3年度稀釋每股盈餘為$4.00", "該公司X3年度稀釋每股盈餘為$4.02", "該公司X3年度稀釋每股盈餘為$4.06"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:29+00:00", "source_pdf_sha1": "998de82ed70f", "answer_pdf_sha1": "6717b96c0f3e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "305", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00288', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-112-e0b1f2ed', 'sub-disabled-6f0ba476-02', NULL, 'single_choice', '甲公司在 X1 年 1 月 1 日發行 2,500 張可轉換公司債。該債券為 4 年期， 票面利率 6%，每張以面額$1,000 發行，自發行債券所收得現金為 $2,500,000。每年於 12 月 31 日付息一次。每張債券可轉換 200 股普通股 ，每股面額$1。類似的不可轉換債券的市場利率為 9%，經計算甲公司可 轉換債券負債部分X1年1月1日的現值為$2,257,033，X2年12月31日 全數轉換。試作X2年12月31日可轉換公司債轉換為普通股的分錄：', '["應付公司債 2,500,000 股本－普通股 500,000 股本溢價－普通股 2,000,000", "資本公積-認股權 242,967 應付公司債 2,500,000 應付公司債折價 242,967 股本－普通股 500,000 股本溢價－普通股 2,000,000", "資本公積－認股權 242,967 應付公司債 2,500,000 應付公司債折價 131,919 股本－普通股 500,000 股本溢價－普通股 2,111,048", "只需附註揭露，不必作分錄 30650"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:29+00:00", "source_pdf_sha1": "998de82ed70f", "answer_pdf_sha1": "6717b96c0f3e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "305", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00289', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-112-e0b1f2ed', 'sub-disabled-6f0ba476-02', NULL, 'single_choice', '甲公司在X1年開始營運，並對其賣出足球產品提供一年的售後服務保證。 甲公司估計X1年賣出的300,000個產品中，會被送回修理的個數有5,000 個，修理成本每個$6。X1年已被送回修理的產品有4,000個，產生修理成 本$24,000。產品的 X1 年保固政策相關交易對甲公司 X1 年會計報表有何 影響？', '["損益表淨利不變，資產負債表的負債增加", "損益表淨利減少，資產負債表的負債增加", "損益表淨利減少，資產負債表的負債不變", "損益表淨利減少，資產負債表的負債減少"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:29+00:00", "source_pdf_sha1": "998de82ed70f", "answer_pdf_sha1": "6717b96c0f3e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "305", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00290', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-112-e0b1f2ed', 'sub-disabled-6f0ba476-02', NULL, 'single_choice', '甲公司最近四年度有關應收帳款 X1 年、X2 年、X3 年和 X4 年期末應收 帳款$28,000、$64,000、$104,000 和$99,000，甲公司採用應收帳款百分比 法估計備抵損失-應收帳款(備抵壞帳科目)，該公司各年底之備抵損失-應 收帳款估計為期末應收帳款餘額之10%，但X4年底結帳前發現錯誤：X2 年應轉銷收不回之應收帳款$12,000 漏未沖銷。該錯誤對各年度淨利之影 響何者正確？', '["X4年淨利高估$12,000", "X4年淨利高估$10,800", "X2年淨利高估$12,000", "X2年淨利高估$10,800"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:29+00:00", "source_pdf_sha1": "998de82ed70f", "answer_pdf_sha1": "6717b96c0f3e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "305", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL)
